mapper.select:
select *
from batch.file_record
where tenant_id = #{tenantId}

    and id = #{fileId}


    and biz_type = #{bizType}


    and file_status = #{fileStatus}


    and file_name ilike concat('%', #{fileName}, '%')


    and trace_id = #{traceId}


    and created_at >= #{fromTime}


    and created_at <= #{toTime}

order by id desc

select metadata_json ->> 'templateCode'
from batch.file_record
where tenant_id = #{tenantId}
  and id = #{fileId}
